static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    const auto *shapeX = context->GetInputShape(0);
    const auto *shapeH = context->GetInputShape(1);
    const auto *shapeW_i2h = context->GetInputShape(2);
